'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';

interface User {
  id: number;
  username: string;
  email: string;
  nickname: string;
  avatar: string;
  bio: string;
  signature: string;
  role: string;
  status: string;
  ban_reason: string;
  admin_remark: string;
  ai_daily_limit: number;
  must_change_password: number;
  last_login_at: string | null;
  created_at: string;
  updated_at: string;
}

export default function UsersPage() {
  const router = useRouter();
  const [users, setUsers] = useState<User[]>([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const [sortBy, setSortBy] = useState('created_at');
  const [sortOrder, setSortOrder] = useState('DESC');
  const [loading, setLoading] = useState(false);

  // 批量操作相关
  const [selectedUsers, setSelectedUsers] = useState<number[]>([]);
  const [showBatchTagDialog, setShowBatchTagDialog] = useState(false);
  const [batchTagMode, setBatchTagMode] = useState<'add' | 'remove'>('add');
  const [batchTagId, setBatchTagId] = useState<number | null>(null);
  const [allTags, setAllTags] = useState<Tag[]>([]);

  const handleExport = async () => {
    const params = new URLSearchParams();
    if (search) params.set('search', search);
    if (statusFilter) params.set('status', statusFilter);
    if (roleFilter) params.set('role', roleFilter);

    try {
      const res = await fetch(`/api/admin/users/export?${params}`);
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `users_${new Date().toISOString().slice(0, 10)}.csv`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        window.URL.revokeObjectURL(url);
      } else {
        const data = await res.json();
        alert(data.error || '导出失败');
      }
    } catch {
      alert('导出失败');
    }
  };

  const loadUsers = async () => {
    setLoading(true);
    const params = new URLSearchParams({
      page: String(page),
      limit: '20',
      sort: sortBy,
      order: sortOrder,
    });
    if (search) params.set('search', search);
    if (statusFilter) params.set('status', statusFilter);
    if (roleFilter) params.set('role', roleFilter);

    try {
      const res = await fetch(`/api/admin/users?${params}`);
      const data = await res.json();
      setUsers(data.users);
      setTotalPages(data.pagination.totalPages);
      setTotal(data.pagination.total);
    } catch {
      console.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadUsers(); }, [page, statusFilter, roleFilter, sortBy, sortOrder]);

  const handleSearch = () => {
    setPage(1);
    loadUsers();
  };

  const handleBan = async (user: User) => {
    const reason = prompt(`请输入封禁 ${user.username} 的原因：`);
    if (reason === null) return;

    const res = await fetch(`/api/admin/users/${user.id}/ban`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ reason }),
    });
    const data = await res.json();
    if (res.ok) {
      loadUsers();
    } else {
      alert(data.error || '封禁失败');
    }
  };

  const handleUnban = async (user: User) => {
    if (!confirm(`确定解封 ${user.username}？`)) return;

    const res = await fetch(`/api/admin/users/${user.id}/unban`, { method: 'PUT' });
    const data = await res.json();
    if (res.ok) {
      loadUsers();
    } else {
      alert(data.error || '解封失败');
    }
  };

  const handleResetPassword = async (user: User) => {
    if (!confirm(`确定重置 ${user.username} 的密码？`)) return;

    const res = await fetch(`/api/admin/users/${user.id}/reset-password`, { method: 'PUT' });
    const data = await res.json();
    if (res.ok) {
      if (data.temp_password) {
        alert(`密码已重置\n临时密码: ${data.temp_password}\n请妥善保管，用户下次登录需修改密码`);
      } else {
        alert('密码已重置');
      }
    } else {
      alert(data.error || '重置失败');
    }
  };

  const toggleSort = (column: string) => {
    if (sortBy === column) {
      setSortOrder(sortOrder === 'DESC' ? 'ASC' : 'DESC');
    } else {
      setSortBy(column);
      setSortOrder('DESC');
    }
    setPage(1);
  };

  const getRoleBadge = (role: string) => {
    switch (role) {
      case 'super_admin': return <span className="px-2 py-0.5 bg-red-500/20 text-red-300 rounded text-xs">超级管理员</span>;
      case 'admin': return <span className="px-2 py-0.5 bg-purple-500/20 text-purple-300 rounded text-xs">管理员</span>;
      default: return <span className="px-2 py-0.5 bg-gray-500/20 text-gray-300 rounded text-xs">普通用户</span>;
    }
  };

  const getStatusBadge = (status: string) => {
    return status === 'active'
      ? <span className="px-2 py-0.5 bg-green-500/20 text-green-300 rounded text-xs">正常</span>
      : <span className="px-2 py-0.5 bg-red-500/20 text-red-300 rounded text-xs">已封禁</span>;
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-white">用户管理 <span className="text-sm text-gray-400 font-normal">({total} 人)</span></h2>
        <button onClick={handleExport} className="px-4 py-2 bg-green-500/20 text-green-300 rounded-lg hover:bg-green-500/30">
          📥 导出CSV
        </button>
      </div>

      {/* 搜索和筛选 */}
      <div className="bg-black/30 backdrop-blur-xl rounded-xl border border-white/10 p-4">
        <div className="flex flex-wrap gap-4 items-center">
          <div className="flex gap-2 flex-1 min-w-[200px]">
            <input
              type="text"
              value={search}
              onChange={e => setSearch(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSearch()}
              placeholder="搜索用户名、邮箱、昵称..."
              className="flex-1 px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-purple-500 text-sm"
            />
            <button onClick={handleSearch} className="px-4 py-2 bg-purple-500/20 text-purple-300 rounded-lg hover:bg-purple-500/30 text-sm">
              🔍 搜索
            </button>
          </div>

          <select
            value={statusFilter}
            onChange={e => { setStatusFilter(e.target.value); setPage(1); }}
            className="px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white text-sm"
          >
            <option value="">全部状态</option>
            <option value="active">正常</option>
            <option value="banned">已封禁</option>
          </select>

          <select
            value={roleFilter}
            onChange={e => { setRoleFilter(e.target.value); setPage(1); }}
            className="px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-white text-sm"
          >
            <option value="">全部角色</option>
            <option value="user">普通用户</option>
            <option value="admin">管理员</option>
            <option value="super_admin">超级管理员</option>
          </select>
        </div>
      </div>

      {/* 用户列表 */}
      <div className="bg-black/30 backdrop-blur-xl rounded-xl border border-white/10 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-gray-400 border-b border-white/10 bg-white/5">
                <th className="p-4">ID</th>
                <th className="p-4">用户</th>
                <th className="p-4">邮箱</th>
                <th className="p-4">角色</th>
                <th className="p-4">状态</th>
                <th className="p-4 cursor-pointer hover:text-white" onClick={() => toggleSort('created_at')}>
                  注册时间 {sortBy === 'created_at' && (sortOrder === 'DESC' ? '↓' : '↑')}
                </th>
                <th className="p-4 cursor-pointer hover:text-white" onClick={() => toggleSort('last_login_at')}>
                  最后登录 {sortBy === 'last_login_at' && (sortOrder === 'DESC' ? '↓' : '↑')}
                </th>
                <th className="p-4">操作</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={8} className="p-8 text-center text-gray-500">加载中...</td></tr>
              ) : users.length === 0 ? (
                <tr><td colSpan={8} className="p-8 text-center text-gray-500">暂无用户</td></tr>
              ) : (
                users.map(user => (
                  <tr key={user.id} className="border-b border-white/5 text-gray-300 hover:bg-white/5">
                    <td className="p-4 text-gray-500">{user.id}</td>
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-indigo-500/20 flex items-center justify-center overflow-hidden">
                          {user.avatar ? (
                            <img src={user.avatar} alt="" className="w-full h-full object-cover" />
                          ) : (
                            <span className="text-indigo-300 text-sm">{(user.nickname || user.username).charAt(0).toUpperCase()}</span>
                          )}
                        </div>
                        <div>
                          <div className="font-medium">{user.nickname || user.username}</div>
                          <div className="text-xs text-gray-500">@{user.username}</div>
                        </div>
                      </div>
                    </td>
                    <td className="p-4 text-sm">{user.email}</td>
                    <td className="p-4">{getRoleBadge(user.role)}</td>
                    <td className="p-4">{getStatusBadge(user.status)}</td>
                    <td className="p-4 text-sm text-gray-500">{new Date(user.created_at).toLocaleDateString('zh-CN')}</td>
                    <td className="p-4 text-sm text-gray-500">{user.last_login_at ? new Date(user.last_login_at).toLocaleDateString('zh-CN') : '-'}</td>
                    <td className="p-4">
                      <div className="flex gap-1 flex-wrap">
                        <button
                          onClick={() => router.push(`/admin/users/${user.id}`)}
                          className="px-2 py-1 bg-blue-500/20 text-blue-300 rounded text-xs hover:bg-blue-500/30"
                        >
                          详情
                        </button>
                        {user.status === 'active' ? (
                          <button
                            onClick={() => handleBan(user)}
                            className="px-2 py-1 bg-red-500/20 text-red-300 rounded text-xs hover:bg-red-500/30"
                          >
                            封禁
                          </button>
                        ) : (
                          <button
                            onClick={() => handleUnban(user)}
                            className="px-2 py-1 bg-green-500/20 text-green-300 rounded text-xs hover:bg-green-500/30"
                          >
                            解封
                          </button>
                        )}
                        <button
                          onClick={() => handleResetPassword(user)}
                          className="px-2 py-1 bg-yellow-500/20 text-yellow-300 rounded text-xs hover:bg-yellow-500/30"
                        >
                          重置密码
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* 分页 */}
      {totalPages > 1 && (
        <div className="flex justify-center gap-2">
          <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1} className="px-4 py-2 bg-white/10 text-white rounded-lg disabled:opacity-50">上一页</button>
          <span className="px-4 py-2 text-gray-400">{page} / {totalPages}</span>
          <button onClick={() => setPage(p => Math.min(totalPages, p + 1))} disabled={page === totalPages} className="px-4 py-2 bg-white/10 text-white rounded-lg disabled:opacity-50">下一页</button>
        </div>
      )}
    </div>
  );
}
